// CLX Outreach Generation — Phase 6
// Parses Claude outreach response and extracts all outreach fields

const response = $input.item.json;
const lead = $('Build Outreach Prompt').item.json;

// Extract text content from Claude API response
const rawText = response.content[0].text;

// Strip markdown code fences and parse JSON
let outreach;
try {
  const cleaned = rawText
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();
  outreach = JSON.parse(cleaned);
} catch (e) {
  outreach = {
    email_subject: 'A thought for ' + (lead.company || 'your business'),
    email_body: 'Hi ' + (lead.full_name || 'there') + ', I came across your work at ' + (lead.company || 'your company') + ' and thought this could be genuinely useful. Worth a quick 15-minute chat?',
    linkedin_message: 'Hi ' + (lead.full_name || '') + ', noticed your work at ' + (lead.company || '') + ' — would love to connect.',
    whatsapp_message: 'Hi ' + (lead.full_name || '') + ', came across your business and had something relevant to share. Would you be open to a quick chat?',
    followup_message: 'Just following up on my previous message — still happy to connect if the timing works better now.',
    outreach_angle: 'Fallback outreach — parse error: ' + e.message,
    personalization_score: 1
  };
}

const now = new Date().toISOString();

return {
  json: {
    ...lead,
    email_subject: outreach.email_subject || '',
    email_body: outreach.email_body || '',
    linkedin_message: outreach.linkedin_message || '',
    whatsapp_message: outreach.whatsapp_message || '',
    followup_message: outreach.followup_message || '',
    outreach_angle: outreach.outreach_angle || '',
    personalization_score: typeof outreach.personalization_score === 'number' ? Math.round(outreach.personalization_score) : 5,
    lead_status: 'Outreach Ready',
    outreach_generated_at: now,
    updated_at: now
  }
};
